const response = $input.first().json;
const data = response.response;
const stations = data.stations;
const date = data.date;

const fuelNames = {
  diesel: 'ดีเซล B7',
  diesel_b20: 'ดีเซล B20',
  premium_diesel: 'ดีเซลพรีเมียม',
  gasohol_95: 'แก๊สโซฮอล์ 95',
  gasohol_91: 'แก๊สโซฮอล์ 91',
  gasohol_e20: 'แก๊สโซฮอล์ E20',
  gasohol_e85: 'แก๊สโซฮอล์ E85',
  benzine_95: 'เบนซิน 95'
};

const stationNames = { ptt: 'PTT', shell: 'Shell', bcp: 'Bangchak' };
let report = 'วันที่: ' + date + '\n';

for (const [sKey, sName] of Object.entries(stationNames)) {
  const s = stations[sKey];
  if (!s) continue;
  report += '\n== ' + sName + ' ==\n';
  for (const [fKey, fName] of Object.entries(fuelNames)) {
    if (s[fKey] && s[fKey].price) {
      report += fName + ': ' + s[fKey].price + ' บาท/ลิตร\n';
    }
  }
}

return [{ json: { prompt: 'สรุปราคาน้ำมันทุกชนิดทุกปั๊มวันนี้ เปรียบเทียบว่าปั๊มไหนถูกกว่า:\n' + report } }];

const response = $input.first().json;
const data = response.response;
const stations = data.stations;
const date = data.date;
const body = $('Webhook (Discord Bot)1').first().json.body;
const channelId = body.channelId || '';
const msg = (body.message || body.content || '').trim();
const msgLower = msg.toLowerCase();
const isChat = body.isChat === true;

const fuelNames = {
  diesel: 'ดีเซล B7',
  diesel_b20: 'ดีเซล B20',
  premium_diesel: 'ดีเซลพรีเมียม',
  gasohol_95: 'แก๊สโซฮอล์ 95',
  gasohol_91: 'แก๊สโซฮอล์ 91',
  gasohol_e20: 'แก๊สโซฮอล์ E20',
  gasohol_e85: 'แก๊สโซฮอล์ E85',
  benzine_95: 'เบนซิน 95'
};

const stationNames = { ptt: 'PTT', shell: 'Shell', bcp: 'Bangchak' };

if (msgLower === '!help') {
  return [{ json: { channelId, prompt: 'แสดงรายการคำสั่งให้สวยงาม: !all (ทุกชนิด), !diesel (ดีเซล B7), !b20 (ดีเซล B20), !d-premium (ดีเซลพรีเมียม), !95 (แก๊สโซฮอล์ 95), !91 (แก๊สโซฮอล์ 91), !e20 (E20), !e85 (E85), !benzine (เบนซิน 95), !compare (เปรียบเทียบทุกปั๊ม), !ask <ข้อความ> (คุยเรื่องน้ำมัน), @OilBot (คุยเรื่องน้ำมัน), !help (คำสั่งทั้งหมด)' } }];
}

let allOilData = 'วันที่: ' + date + '\n';
for (const [sKey, sName] of Object.entries(stationNames)) {
  const s = stations[sKey];
  if (!s) continue;
  allOilData += '\n== ' + sName + ' ==\n';
  for (const [fKey, fName] of Object.entries(fuelNames)) {
    if (s[fKey] && s[fKey].price) {
      allOilData += fName + ': ' + s[fKey].price + ' บาท/ลิตร\n';
    }
  }
}

if (isChat) {
  const promptText = 'ผู้ใช้ถามว่า: ' + msg + '\n\nข้อมูลราคาน้ำมันล่าสุด:\n' + allOilData;
  return [{ json: { channelId, prompt: promptText } }];
}

const cmdMap = {
  '!all': Object.keys(fuelNames),
  '!diesel': ['diesel'],
  '!95': ['gasohol_95'],
  '!91': ['gasohol_91'],
  '!e20': ['gasohol_e20'],
  '!e85': ['gasohol_e85'],
  '!benzine': ['benzine_95'],
  '!b20': ['diesel_b20'],
  '!d-premium': ['premium_diesel'],
  '!compare': Object.keys(fuelNames)
};

const fuelKeys = cmdMap[msgLower] || Object.keys(fuelNames);
const isCompare = msgLower === '!compare';

let info = 'วันที่: ' + date + '\n';
for (const [sKey, sName] of Object.entries(stationNames)) {
  const s = stations[sKey];
  if (!s) continue;
  info += '\n== ' + sName + ' ==\n';
  for (const fKey of fuelKeys) {
    if (s[fKey] && s[fKey].price) {
      info += (fuelNames[fKey] || fKey) + ': ' + s[fKey].price + ' บาท/ลิตร\n';
    }
  }
}

let promptText = '';
if (isCompare) {
  promptText = 'เปรียบเทียบราคาน้ำมันระหว่างปั๊ม แนะนำว่าปั๊มไหนถูกที่สุดแต่ละชนิด:\n' + info;
} else if (msgLower === '!all') {
  promptText = 'แสดงราคาน้ำมันทั้งหมดทุกปั๊ม:\n' + info;
} else {
  promptText = 'ผู้ใช้สั่ง ' + msgLower + ' แสดงราคาเฉพาะตัว:\n' + info;
}

return [{ json: { channelId, prompt: promptText } }];

const response = $input.first().json;
const data = response.response;
const stations = data.stations;
const staticData = $getWorkflowStaticData('global');

const fuelKeys = ['diesel', 'diesel_b20', 'premium_diesel', 'gasohol_95', 'gasohol_91', 'gasohol_e20', 'gasohol_e85'];
const stationNames = { ptt: 'PTT', shell: 'Shell', bcp: 'Bangchak' };
const fuelNames = { diesel: 'ดีเซล B7', diesel_b20: 'ดีเซล B20', premium_diesel: 'ดีเซลพรีเมียม', gasohol_95: 'แก๊สโซฮอล์ 95', gasohol_91: 'แก๊สโซฮอล์ 91', gasohol_e20: 'แก๊สโซฮอล์ E20', gasohol_e85: 'แก๊สโซฮอล์ E85' };

const currentPrices = {};
for (const [sKey, sName] of Object.entries(stationNames)) {
  const s = stations[sKey];
  if (!s) continue;
  for (const fKey of fuelKeys) {
    if (s[fKey] && s[fKey].price) {
      currentPrices[sKey + '_' + fKey] = s[fKey].price;
    }
  }
}

const prev = staticData.previousPrices || {};
const changes = [];

for (const [key, val] of Object.entries(currentPrices)) {
  if (prev[key] !== undefined && prev[key] !== val) {
    const diff = val - prev[key];
    const parts = key.split('_');
    const station = (stationNames[parts[0]] || parts[0]).toUpperCase();
    const fuel = parts.slice(1).join('_');
    const fName = fuelNames[fuel] || fuel;
    const arrow = diff > 0 ? 'ขึ้น' : 'ลง';
    changes.push(station + ' ' + fName + ': ' + prev[key] + ' -> ' + val + ' (' + arrow + ' ' + Math.abs(diff).toFixed(2) + ' บาท)');
  }
}

staticData.previousPrices = currentPrices;

if (changes.length === 0) return [];

return [{ json: { prompt: 'ราคาน้ำมันเปลี่ยนแปลง! แจ้งเตือนผู้ใช้:\n\nวันที่: ' + data.date + '\n\nรายการที่เปลี่ยน:\n' + changes.join('\n') } }];
